return ['x-generator'=>'GlotPress/4.0.1','translation-revision-date'=>'2024-12-24 09:25:57+0000','plural-forms'=>'nplurals=2; plural=n != 1;','project-id-version'=>'Plugins - Contextual Related Posts - Stable (latest release)','language'=>'es','messages'=>['Note: This setting cannot be changed as the Thumbnail style is set to Text Only. You can change the style in the Styles tab.'=>'Nota: Este ajuste no se puede cambiar ya que el estilo de la miniatura se ha establecido a solo texto. Puedes cambiar el estilo en la pestaña de estilos.','Note: This setting cannot be changed as the Thumbnail style is set to Rounded Thumbnails or Rounded Thumbnails with Grid. You can change the style in the Styles tab.'=>'Nota: Este ajuste no se puede cambiar ya que el estilo de la miniatura se ha establecido a miniaturas redondeadas o miniaturas redondeadas con cuadrícula. Puedes cambiar el estilo en la pestaña de estilos.','If activated, the settings from this page are automatically inserted in the Related Posts block. This also applies to existing blocks which do not have any attributes set if the post is edited.'=>'Si se activa, los ajustes de esta página se insertan automáticamente en el bloque de entradas relacionadas. Esto también se aplicará a los bloques existentes que no tengan configurado ningún atributo cuando se editó la entrada.','Use global settings in block'=>'Usar ajustes globales en el bloque','Clear the Contextual Related Posts cache. This might take a while if you have a lot of posts.'=>'Vacía la caché de Contextual Related Posts. Esto podría tardar un rato si tienes montones de entradas.','Select how you want the related posts to be ordered. Randomly will shuffle the related posts and does not work if you have HTML caching enabled.'=>'Selecciona cómo quieres que se ordenen las entradas relacionadas. Aleatoriamente mezclará las entradas relacionadas y no funciona si tienes activada la caché HTML.','Comma separated list of category slugs. The field above has an autocomplete so simply start typing in the starting letters and it will prompt you with options. Does not support custom taxonomies.'=>'Lista de categorías separadas por comas. El campo de arriba tiene un autocompletado, así que simplemente empieza a escribir las letras iniciales y se le pedirá con opciones. No admite taxonomías personalizadas.','Contextual Related Posts and Contextual Related Posts PRO should not be active at the same time. We\'ve automatically deactivated Contextual Related Posts PRO.'=>'Contextual Related Posts y Contextual Related Posts PRO no deberían estar activos al mismo tiempo. Hemos desactivado automáticamente Contextual Related Posts PRO.','Contextual Related Posts and Contextual Related Posts PRO should not be active at the same time. We\'ve automatically deactivated Contextual Related Posts.'=>'Contextual Related Posts y Contextual Related Posts PRO no deberían estar activos al mismo tiempo. Hemos desactivado automáticamente Contextual Related Posts.','Follow us'=>'Síguenos','Auto Close'=>'Cierre automático','Popular Authors'=>'Autores populares','Followed Posts'=>'Entradas seguidas','Snippetz'=>'Snippetz','Better Search'=>'Better Search','Top 10'=>'Top 10','WebberZone plugins'=>'Plugins de WebberZone','Knowledge Base'=>'Base de conocimiento','Support the development - Send us a donation today.'=>'Apoya el desarrollo - Envíanos hoy un donativo','Contextual Related Posts Pro - Buy now!'=>'Contextual Related Posts Pro - ¡Comprarlo ahora!','Upgrade to Pro'=>'Actualiza a la versión Pro','Reset'=>'Restablecer','Thank you for using %1$sContextual Related Posts by WebberZone%2$s! Please %3$srate us%2$s on %3$sWordPress.org%2$s'=>'¡Gracias por usar %1$sContextual Related Posts de WebberZone%2$s! Por favor, %3$svalóranos%2$s en %3$sWordPress.org%2$s','You can choose from existing image sizes above or create a custom size. If you have chosen Custom size above, then enter the width, height and crop settings below. For best results, use a cropped image. If you change the width and/or height below, existing images will not be automatically resized. You will ned to regenerate the images using a plugin or using WP CLI: wp media regenerate.'=>'Puedes elegir entre los tamaños de imagen existentes arriba o crear un tamaño personalizado. Si has elegido un tamaño personalizado, introduce los valores de anchura, altura y recorte a continuación. Para obtener mejores resultados, utiliza una imagen recortada. Si cambias la anchura y/o la altura, las imágenes existentes no se redimensionarán automáticamente. Tendrás que regenerar las imágenes usando un plugin o usando WP CLI: wp media regenerate.','This sets the maximum words of the post content that will be matched. Set to 0 for no limit. Max value: %1$s.'=>'Establece el máximo de palabras del contenido de la entrada que se compararán. Pon 0 para no tener límite. Valor máximo: %1$s.','The weight to give to the post excerpt when calculating the relevance of the post.'=>'El peso que debe darse al extracto de la entrada al calcular la relevancia de la misma.','Weight for post excerpt'=>'Peso del extracto de la entrada','The weight to give to the post content when calculating the relevance of the post.'=>'El peso que debe darse al contenido de la entrada al calcular la relevancia de la misma.','Weight for post content'=>'Peso del contenido de la entrada','The weight to give to the post title when calculating the relevance of the post.'=>'El peso que debe darse al título de la entrada al calcular la relevancia de la misma.','Weight for post title'=>'Peso del título de la entrada','This ignores any other HTML tags and can get confused by p tags within other tags. Use with caution.'=>'Esto ignora cualquier otra etiqueta HTML y puede confundirse con etiquetas p dentro de otras etiquetas. Utilízalo con precaución.','Enter 0 to display the related posts before the post content, -1 to display this at the end, or a number to insert after a specific paragraph. For negative numbers, the count starts from the end. If the paragraph number exceeds the post\'s count, they\'ll appear at the end.'=>'Pon 0 para mostrar las entradas relacionadas antes del contenido de la entrada, -1 para mostrarlo al final, o un número para insertarlo después de un párrafo específico. Para números negativos, el recuento comienza desde el final. Si el número del párrafo excede el recuento de la entrada, aparecerán al final.','Enabling this will cache the entire HTML generated when the post is visited the first time. The cache is cleaned when you save this page. Highly recommended particularly on busy sites. Default is true.'=>'Al activar esta opción, se almacenará en caché todo el HTML generado cuando se visite la entrada por primera vez. La caché se limpia al guardar la página. Muy recomendable, especialmente en sitios con mucho tráfico. Por defecto es true.','Choose File'=>'Elegir archivo','The callback function used for the %1$s setting is missing.'=>'No existe la función retorno usada para el ajuste de %1$s.','Used to specify the order in which the code snippets are added to the content. Lower numbers correspond with earlier addition, and functions with the same priority are added in the order in which they were added, typically by post ID.'=>'Se utiliza para especificar el orden en que se añaden los fragmentos de código al contenido. Los números más bajos corresponden a una inserción anterior, y las funciones con la misma prioridad se añaden en el orden en que se añadieron, normalmente por ID de entrada.','Priority'=>'Prioridad','Step 3: Priority'=>'Paso 3: Prioridad','Include on these Tags'=>'Incluir en estas etiquetas','Include on these Categories'=>'Incluir en estas categorías','Enter a comma-separated list of post, page or custom post type IDs on which to include the code. Any incorrect ids will be removed when saving.'=>'Introduce una lista separada por comas de IDs de entradas, páginas o tipos de contenido personalizados en los que incluir el código. Cualquier ID incorrecto se eliminará al guardar.','Include on these Post IDs'=>'Incluir en estos ID de entrada','Select on which post types to display the contents of this snippet.'=>'Selecciona en qué tipos de contenido mostrar los contenidos de este fragmento de código.','Include on these post types'=>'Incluir en estos tipos de contenido','AND'=>'AND','OR'=>'OR','Selecting OR would match any of the condition below and selecting AND would match all the conditions below.'=>'Seleccionando OR coincidiría cualquiera de las condiciones de abajo y seleccionando AND coincidirían todas las condiciones de abajo.','The logical relationship between each condition below'=>'La relación lógica entre cada condición de las siguientes','Select at least one condition below to display the contents of this snippet. Leaving any of the conditions blank will ignore it. Leaving all blank will ignore the snippet. If you want to include the snippet on all posts, then you can use the Global Settings.'=>'Selecciona al menos una condición para mostrar el contenido de este fragmento. Si dejas alguna de las condiciones en blanco, la ignorarás. Si dejas todas en blanco, ignorarás el fragmento. Si quieres incluir el fragmento en todas las entradas, puedes utilizar los ajustes globales.','Step 2: Conditions'=>'Paso 2: Condiciones','When enabled the contents of this snippet are automatically added after the content of posts based on the selection below.'=>'Cuando se activa, el contenido de este fragmento se añade automáticamente después del contenido de las entradas en función de la selección realizada a continuación.','Add after Content'=>'Añadir después del contenido','When enabled the contents of this snippet are automatically added before the content of posts based on the selection below.'=>'Cuando se activa, el contenido de este fragmento se añade automáticamente antes del contenido de las entradas en función de la selección realizada a continuación.','Add before Content'=>'Añadir antes del contenido','Add to Footer'=>'Añadir al pie de página','Add to Header'=>'Añadir a la cabecera','Step 1: Where to display this'=>'Paso 1: Dónde mostrar esto','CSS'=>'CSS','Javascript'=>'Javascript','HTML'=>'HTML','Select the type of snippet you want to add. You will need to update/save this page in order to update the editor format above.'=>'Selecciona el tipo de fragmento que deseas añadir. Tendrás que actualizar/guardar esta página para actualizar el formato del editor anterior.','Snippet Type'=>'Tipo de fragmento de código','Modified from default'=>'Modificado a partir del valor por defecto','Start typing to find related posts'=>'Empieza a teclear para encontrar entradas relacionadas','Include'=>'Incluir','Exclude'=>'Excluir','&mdash; No Change &mdash;'=>'&mdash; Sin cambios &mdash;','Exclude from related posts'=>'Excluir de las entradas relacionadas','Exclude this post from related posts'=>'Excluir esta entrada de las entradas relacionadas','Comma-separated list of post IDs'=>'Lista de IDs de entrada separadas por comas','(0 to clear the manual posts)'=>'(0 para vaciar las entradas manuales)','Manual Related Posts'=>'Entradas relacionadas manuales','Exclude from list:'=>'Excluir de la lista:','Enter a comma-separated list of meta keys. Posts that match the same value of the meta key are displayed before the other related posts'=>'Introduce una lista de claves meta separadas por comas. Lasa entradas en las que coincida el mismo valor de la clave meta se muestran antes que el resto de entradas relacionadas.','Related Meta Keys'=>'Claves meta relacionadas','Related Posts Tools'=>'Herramientas de entradas relacionadas','No related posts were found or the block rendered empty. Please modify your block settings.'=>'No se encontraron entradas relacionadas o el bloque se procesó vacío. Por favor, modifica los ajustes de tu bloque.','Contextual Related Posts Block'=>'Bloque de entradas relacionadas contextuales','block descriptionDisplay the Related Posts'=>'Muestra las entradas relacionadas','block keywordcontextual'=>'contextual','block keywordposts'=>'entradas','block keywordrelated posts'=>'entradas relacionadas','block titleContextual Related Posts'=>'Entradas relacionadas contextuales','Only from categories (comma-separated list of term taxonomy IDs)'=>'Solo a partir de categorías (lista de IDs de términos de taxonomía separados por comas)','cropped'=>'recortado','Excluded posts:'=>'Entradas excluidas:','Comma separated list of post, page or custom post type IDs. e.g. 188,320,500.'=>'Lista separada por comas de IDs de entradas, paginas o tipos de contenido personalizados. P.ej.: 188, 320, 500.','Exclude post IDs:'=>'Excluir IDs de entradas:','Exclude Term Taxonomy IDs'=>'Excluir IDs de términos de taxonomía','Exclude Terms'=>'Excluir términos','If enabled, then it will only select posts from the primary category/term. This is usually set via your SEO plugin and will default to the first category/term returned by WordPress'=>'Si está activada, sólo seleccionará las entradas de la categoría/término principal. Esto se establece generalmente a través de tu plugin SEO y por defecto será la primera categoría/término devuelto por WordPress.','Limit to same primary term'=>'Limitar al mismo término principal','The field above has an autocomplete so simply start typing in the starting letters and it will prompt you with options. This field requires a specific format as displayed by the autocomplete.'=>'El campo anterior tiene una función de autocompletar, por lo que sólo tienes que empezar a escribir las letras iniciales y se te ofrecerán opciones. Este campo requiere un formato específico que muestra el autocompletado.','Exclude on Terms'=>'Excluir en términos','This will display the primary category/term. This is usually set via your SEO plugin and will default to the first category/term returned by WordPress'=>'Esto mostrará la categoría/término principal. Normalmente se configura a través de tu plugin SEO y por defecto será la primera categoría/término devuelta por WordPress.','Show primary category/term'=>'Mostrar categoría/término principal','Taxonomy IDs from which posts are excluded (comma separated)'=>'ID de taxonomía de los que se excluyen las entradas (separados por comas)','Post/page IDs to exclude (comma separated)'=>'IDs de aentrada/página a excluir (separados por comas)','Same author'=>'Mismo autor','Same post type'=>'Mismo tipo de contenido','Post types (comma separated)'=>'Tipos de contenido (separados por comas)','Number of posts'=>'Número de entradas','Post ID.'=>'ID de la entrada.','Invalid post ID.'=>'ID de entrada no válido.','Enter a comma-separated list of terms. If a related post\'s title or content contains any of these terms then it will be excluded from the results.'=>'Introduce una lista de términos separados por comas. Si el título o el contenido de una entrada relacionada contiene alguno de estos términos, se excluirá de los resultados.','Exclude terms:'=>'Excluir términos:','Cache has been cleared'=>'Se ha vaciado la caché','Uses CSS grid. It will also turn off the display of the author, excerpt and date if already enabled. Disabling this option will not revert any settings.'=>'Utiliza la cuadrícula CSS. También desactivará la visualización del autor, el extracto y la fecha si ya están activados. Desactivar esta opción no revertirá ningún ajuste.','Rounded thumbnails with CSS grid'=>'Miniaturas redondeadas con cuadrícula CSS','Uses CSS Grid for display. Might not work on older browsers.'=>'Usa cuadrícula CSS para la visualización. Podría no funcionar en navegadores antiguos.','Grid'=>'Cuadrícula','Enables a masonry style layout similar to one made famous by Pinterest.'=>'Activa un estilo de diseño de mosaico, similar al que se hizo famoso por Pinterest.','Masonry'=>'Mosaico','Applies only if the previous option is checked. Selecting this option will retain contextual matching for posts and pages but disable this on any custom post types.'=>'Sólo se aplica si está marcada la opción anterior. Al seleccionar esta opción se mantendrá la concordancia contextual para entradas y páginas, pero se desactivará para cualquier tipo de contenido personalizado.','Disable contextual matching ONLY on attachments and custom post types'=>'Desactivar la concordancia contextual SÓLO en adjuntos y tipos de contenido personalizados','Selecting this option will turn off contextual matching. This is only useful if you activate the option: "Only from same" from the General tab. Otherwise, you will end up with the same set of related posts on all pages with no relevance.'=>'Al seleccionar esta opción se desactivará la concordancia contextual. Esto sólo es útil si activa la opción «Sólo desde el mismo» en la pestaña general. De lo contrario, acabará con el mismo conjunto de entradas relacionadas en todas las páginas sin relevancia.','Disable contextual matching'=>'Desactivar concordancia contextual','Enter the minimum number of common terms that have to be matched before a post is considered related.'=>'Introduce el número mínimo de términos comunes que deben coincidir para que una entrada se considere relacionada.','Number of common terms'=>'Número de términos comunes','If enabled, then it will only select posts that match all the above selected taxonomies. This can result in no related posts being found.'=>'Si se activa, sólo se seleccionarán las entradas que coincidan con todas las taxonomías seleccionadas. Esto puede hacer que no se encuentren entradas relacionadas.','Match all taxonomies'=>'Coincidencia de todas las taxonomías','Limit the related posts only to the categories, tags, and/or taxonomies of the current post.'=>'Limita las entradas relacionadas sólo a las categorías, etiquetas y/o taxonomías de la entrada actual.','Only from same'=>'Solo de las mismas','You can find more information on each of these tools in this <a href="%1$s" target="_blank">knowledgebase article</a>.'=>'Puedes encontrar más información sobre cada una de estas herramientas en este <a href="%1$s" target="_blank">artículo de la base de conocimiento</a>.','Clear the cache, recreate the fulltext indices (including code to manually run this in phpMyAdmin), export/import settings and delete the older settings.'=>'Vacía la caché, vuelve a crear los índices de texto completo (incluido el código para ejecutarlo manualmente en phpMyAdmin), exporta/importa los ajustes y elimina los ajustes antiguos.','You can find detailed information on each of the settings in these <a href="%1$s" target="_blank">knowledgebase articles</a>.'=>'Puedes encontrar más información sobre cada uno de estos ajustes en estos <a href="%1$s" target="_blank">artículos de la base de conocimiento</a>.','<a href="%1$s" target="_blank">Post an issue</a> on <a href="%2$s" target="_blank">GitHub</a> (bug reports only).'=>'<a href="%1$s" target="_blank">Publica un problema</a> en <a href="%2$s" target="_blank">GitHub</a> (solo para informar de fallos).','(more&hellip;)'=>'(más&hellip;)','Continue reading %s'=>'Sigue leyendo %s','If this is checked, FULLTEXT indices generated by Contextual Related Posts are removed from the database if you choose to deactivate the plugin.'=>'Si está marcada, los índices FULLTEXT generados por Contextual Related Posts se eliminan de la base de datos si decides desactivar el plugin.','Delete FULLTEXT indices on deactivate'=>'Borrar índices FULLTEXT al desactivar','There is no excerpt because this is a protected post.'=>'No hay extracto porque es una entrada protegida.','Settings updated.'=>'Ajustes actualizados.','Settings have been reset to their default values. Reload this page to view the updated settings.'=>'Los ajustes han sido restablecidos a sus valores por defecto. Recarga esta página para ver los ajustes actualizados.','Tools'=>'Herramientas','tag delimiter,'=>',','Modified from default setting'=>'Modificado del ajuste por defecto','Feed'=>'Feed','Output'=>'Resultado','List tuning'=>'Refinar el listado','Reset all settings'=>'Restablecer todos los ajustes','Do you really want to reset all these settings to their default values?'=>'¿Seguro que quieres restablecer todos estos ajustes a sus valores por defecto?','Save Changes'=>'Guardar cambios','Visit the Tools page'=>'Visita la página de herramientas','Contextual Related Posts Settings'=>'Ajustes de entradas relacionadas contextuales','Ajay\'s blog'=>'Blog de Ajay','Github repository'=>'Repositorio de GitHub','Reviews'=>'Valoraciones','Contextual Related Posts homepage'=>'Página de inicio de entradas relacionadas contextuales','Quick links'=>'Enlaces rápidos','Please upload a file to import'=>'Por favor, sube un archivo para importarlo','Please upload a valid .json file'=>'Por favor, sube un archivo .json válido','Import Settings'=>'Ajustes de importación','Import the plugin settings from a .json file. This file can be obtained by exporting the settings on another site using the form above.'=>'Importar los ajustes del plugin desde un archivo .json. Este archivo se puede obtener mediante la exportación de los ajustes en otro sitio usando el formulario de arriba.','Export Settings'=>'Ajustes de exportación','Export the plugin settings for this site as a .json file. This allows you to easily import the configuration into another site.'=>'Exportar los ajustes del plugin de este sitio como un archivo .json. Esto te permite importar fácilmente los ajustes en otro sitio.','Export/Import settings'=>'Ajustes de exportación/importación','Deletes and recreates the FULLTEXT index in the posts table. If the above function gives an error, then you can run the below code in phpMyAdmin or Adminer. Remember to backup your database first!'=>'Borra y vuelve a crear el índice FULLTEXT en la tabla posts. Si la función anterior da un error, entonces puedes ejecutar el siguiente código en phpMyAdmin o Adminer. Recuerda hacer primero una copia de seguridad de tu base de datos.','Recreate Indices'=>'Recrear índices','Clear cache'=>'Vaciar caché','Visit the Settings page'=>'Visita la página de ajustes','Contextual Related Posts Tools'=>'Herramientas de entradas relacionadas contextuales','Settings have been imported successfully'=>'Los ajustes se han importado correctamente','Indices have been recreated'=>'Se han recreado los índices','Contribute'=>'Colaborar','Donate'=>'Donar','Support'=>'Soporte','Settings'=>'Opciones','You have Top 10 WordPress Plugin installed. If you are trying to modify the thumbnail, then you\'ll need to make the same change in the Top 10 meta box on this page.'=>'Tienes el plugin Top 10 WordPress instalado. Si estás intentando modificar la miniatura, entonces tendrás que hacer el mismo cambio en la caja meta de Top 10 en esta página.','The URL above is saved in the meta field:'=>'La URL de arriba se ha guardado en el campo meta:','Enter the full URL to the image (JPG, PNG or GIF) you\'d like to use. This image will be used for the post. It will be resized to the thumbnail size set under Settings &raquo; Related Posts &raquo; Output Options'=>'Introduce la URL completa de la imagen (JPG, PNG o GIF) que deseas utilizar. Esta imagen se utilizará para la entrada. Se redimensionará al tamaño de miniatura establecido en Ajustes &raquo; Entradas relacionadas &raquo; Opciones de salida.','Location of thumbnail'=>'Ubicación de la miniatura','This post type is: %s'=>'Este tipo de contenido es: %s','Manual related posts:'=>'Entradas relacionadas manuales:','Enter either a word or a phrase that will be used to find related posts. If entered, the plugin will continue to search the `post_title` and `post_content` fields but will use this keyword instead of the values of the title and content of this post.'=>'Introduce una palabra o una frase que se utilizará para encontrar entradas relacionadas. Si se introduce, el plugin seguirá buscando en los campos `post_title` y `post_content` pero utilizará esta palabra clave en lugar de los valores del título y contenido de esta entrada.','Keyword:'=>'Palabra clave:','If this is checked, then this post will be excluded from the popular posts list.'=>'Si está marcada, esta entrada será excluida de la lista de entradas populares.','Exclude this post from the related posts list:'=>'Excluir esta entrada de la lista de entradas relacionadas:','If this is checked, then Contextual Related Posts will not automatically insert the related posts at the end of post content.'=>'Si está marcada esta opción, las entradas relacionadas contextuales no se insertarán automáticamente al final del contenido de la entrada.','Disable Related Posts display:'=>'Desactivar la visualización de entradas relacionadas:','By date'=>'Por fecha','Randomly'=>'Aleatoriamente','By relevance'=>'Por relevancia','Enabling this option will turn on the thumbnails. It will also turn off the display of the author, excerpt and date if already enabled. Disabling this option will not revert any settings.'=>'Al activar esta opción se activarán las miniaturas. También desactivará la visualización del autor, el extracto y la fecha si ya están activados. Desactivar esta opción no revertirá ningún ajuste.','Rounded thumbnails'=>'Miniaturas redondeadas','Disable thumbnails and no longer include the default style sheet'=>'Desactivar las miniaturas y dejar de incluir la hoja de estilo por defecto','Text only'=>'Solo texto','Select this option if you plan to add your own styles'=>'Selecciona esta opción si tienes pensado añadir tus propios estilos','No styles'=>'Sin estilos','Below options override the related posts settings for your blog feed. These only apply if you have selected to add related posts to Feeds in the General Options tab. It is recommended to not display thumbnails as there is no easy way to style the related posts in the feed.'=>'Las siguientes opciones anulan los ajustes de entradas relacionadas para el feed de tu blog. Sólo se aplican si ha seleccionado añadir entradas relacionadas a los feeds en la pestaña de opciones generales. Se recomienda no mostrar miniaturas, ya que no hay una manera fácil de dar estilo a las entradas relacionadas en el feed.','About this tab'=>'Acerca de esta pestaña','Do not include %3$sstyle%4$s tags. Check out the %1$sFAQ%2$s for available CSS classes to style.'=>'No incluir etiquetas de %3$sestilo%4$s. Revisa la %1$sFAQ%2$s para saber qué clases CSS hay disponibles para aplicar estilos.','Custom CSS'=>'CSS personallizado','Related Posts style'=>'Estilo de las entradas relacionadas','Enter the full URL of the image that you wish to display if no thumbnail is found. This image will be displayed below.'=>'Introduce la URL completa de la imagen que deseas mostrar si no se encuentra ninguna miniatura. Esta imagen se mostrará debajo.','Default thumbnail'=>'Miniatura por defecto','If checked, when no thumbnail is found, show a default one from the URL below. If not checked and no thumbnail is found, no image will be shown.'=>'Si está marcada, cuando no se encuentre ninguna miniatura, mostrará una por defecto desde la URL de abajo. Si no está marcada y no se encuentra ninguna miniatura, no se mostrará ninguna imagen.','Use default thumbnail?'=>'¿Usar la miniatura por defecto?','The plugin will fetch the first image in the post content if this is enabled. This can slow down the loading of your page if the first image in the followed posts is large in file-size.'=>'El plugin buscará la primera imagen en el contenido de la entrada si esta opción está activada. Esto puede ralentizar la carga de tu página si la primera imagen en las entradas seguidas es grande en tamaño de archivo.','Get first image'=>'Obtener la primera imagen','The value of this field should contain the URL of the image and can be set in the metabox in the Edit Post screen'=>'El valor de este campo debe contener la URL de la imagen y puede establecerse en la caja metabox de la pantalla de edición de la entrada.','Thumbnail meta field name'=>'Nombre del campo meta de la miniatura','No width or height set. You will need to use external styles to force any width or height of your choice.'=>'No se ha definido ancho ni altura. Tendrás que usar estilos externos para forzar cualquier ancho o alto que elijas.','Use HTML attributes to set the width and height: e.g. %s'=>'Usa atributos HTML para definir el ancho y alto: P.ej.: %s','Use CSS to set the width and height: e.g. %s'=>'Usa CSS para definir el ancho y alto: P.ej.: %s','Thumbnail size attributes'=>'Atributos de tamaño de la miniatura','If you select this option and Custom size is selected above, the plugin will register the image size with WordPress to create new thumbnails. Does not update old images as explained above.'=>'Si seleccionas esta opción y arriba seleccionas el tamaño personalizado, el plugin registrará el tamaño de la imagen con WordPress para crear nuevas miniaturas. No actualiza las imágenes antiguas como se explicó anteriormente.','Generate thumbnail sizes'=>'Generar tamaños de miniatura','Check this box to hard crop the thumbnails. i.e. force the width and height above vs. maintaining proportions.'=>'Marca esta casilla para forzara el recorte de las miniaturas. O sea, para forzar el ancho y alto de arriba pero sin mantener las proporciones.','Hard crop thumbnails'=>'Recorte forzado de miniaturas','Thumbnail size'=>'Tamaño de la miniatura','Do not display thumbnails, only text'=>'No mostrar miniaturas, solo texto','Display only thumbnails, no text'=>'Solo miniaturas, sin texto','Display thumbnails inline with posts, after title'=>'Muestra miniaturas incrustadas con las entradas, después del título','Display thumbnails inline with posts, before title'=>'Muestra miniaturas incrustadas con las entradas, antes del título','Location of the post thumbnail'=>'Ubicación de la miniatura de la entrada','This is a readonly field that is automatically populated based on the above input when the settings are saved. These might differ from the IDs visible in the Categories page which use the term_id. Contextual Related Posts uses the term_taxonomy_id which is unique to this taxonomy.'=>'Se trata de un campo de sólo lectura que se rellena automáticamente en función de la entrada anterior cuando se guardan los ajustes. Estos pueden diferir de los IDs visibles en la página de categorías que usa el term_id. Contextual Related Posts utiliza el term_taxonomy_id que es único para esta taxonomía.','Comma separated list of tag slugs. The field above has an autocomplete so simply start typing in the starting letters and it will prompt you with options. Does not support custom taxonomies.'=>'Lista de slugs de etiquetas separados por comas. El campo de arriba tiene un autocompletado, así que simplemente empieza a escribir las letras iniciales y te preguntará con opciones. No admite taxonomías personalizadas.','Comma-separated list of post or page IDs to exclude from the list. e.g. 188,320,500'=>'Lista separada por comas de IDs de entradas o páginas a excluir de la lista. P.ej.: 188,320,500','Post/page IDs to exclude'=>'IDs de entrada/página a excluir','If checked, the related posts will only be selected from the same author of the current post.'=>'Si se marca, las entradas relacionadas solo serán seleccionadas entre las del mismo autor de la entrada actual.','Limit to same author'=>'Limitar al mismo autor','If checked, the related posts will only be selected from the same post type of the current post.'=>'Si está marcada, las entradas relacionadas sólo se seleccionarán del mismo tipo de contenido que la entrada actual.','Limit to same post type'=>'Limitar al mismo tipo de contenido','At least one option should be selected above. Select which post types you want to include in the list of posts. This field can be overridden using a comma separated list of post types when using the manual display.'=>'Al menos una de las opciones anteriores debe estar seleccionada. Selecciona qué tipos de contenido quieres incluir en la lista de entradas. Este campo puede anularse utilizando una lista de tipos de contenido separada por comas cuando se utiliza la visualización manual.','Limit content to be compared'=>'Limitar el contenido a comparar','If unchecked, only posts titles are used. Enable the cache if enabling this option for better performance. Each site is different, so toggle this option to see which setting gives you better quality related posts.'=>'Si no está marcada, sólo se utilizan los títulos de las entradas. Activa la caché si activas esta opción para mejorar el rendimiento. Cada sitio es diferente, por lo que alternar esta opción para ver qué ajuste te da entradas relacionadas de mejor calidad.','Related posts based on title and content'=>'Entradas relacionadas basadas en el título y el contenido','This shuffles the selected related posts, similar to choosing Randomly in the above option. If you select to order by date in the previous option, then the related posts will first be sorted by date and the selected ones are shuffled. Does not work if Cache HTML output is enabled.'=>'Esto mezcla las entradas relacionadas seleccionadas, de forma similar a elegir aleatoriamente en la opción anterior. Si selecciona ordenar por fecha en la opción anterior, entonces las entradas relacionadas se ordenarán primero por fecha y las seleccionadas se mezclarán. No funciona si la opción de caché HTML está activada.','Randomize posts'=>'Entradas aleatorias','This sets the cut-off period for which posts will be displayed. e.g. setting it to 365 will show related posts from the last year only. Set to 0 to disable limiting posts by date.'=>'Establece el periodo límite para el que se mostrarán las entradas. Por ejemplo, si se establece en 365, sólo se mostrarán las entradas relacionadas del último año. Ajústalo a 0 para desactivar la limitación de publicaciones por fecha.','Related posts should be newer than'=>'Las entradas relacionadas deben ser más recientes que','Maximum number of posts that will be displayed in the list. This option is used if you do not specify the number of posts in the widget or shortcodes'=>'Número máximo de entradas que se mostrarán en la lista. Esta opción se utiliza si no se especifica el número de entradas en el widget o shortcodes.','Number of posts to display'=>'Número de entradas a mostrar','After each list item'=>'Después de cada elemento de la lista','Before each list item'=>'Antes de cada elemento de la lista','After the list of posts'=>'Después de la lista de entradas','Before the list of posts'=>'Antes de la lista de entradas','HTML to display'=>'HTML a mostrar','The related posts will not display on any of the above selected post types.'=>'Las entradas relacionadas no se mostrarán en ninguno de los tipos de contenido seleccionados arriba.','Exclude display on these post types'=>'Excluir la visualización en estos tipos de contenido','Comma separated list of post, page or custom post type IDs. e.g. 188,320,500'=>'Lista separada por comas de ID de entradas, páginas o tipos de contenido personalizados. P. ej.: 188.320.500','Exclude display on these posts'=>'Excluir la visualización en estas entradas','Exclusion settings'=>'Ajustes de exclusión','Add nofollow to links'=>'Añadir «nofollow» a los enlaces','Open links in new window'=>'Abrir enlaces en una nueva ventana','Any title longer than the number of characters set above will be cut and appended with an ellipsis (&hellip;)'=>'Cualquier título que sea más largo que el número de caracteres definido arriba se cortará y se añadirá una elipsis (&hellip;)','Limit post title length (in characters)'=>'Limitar la longitud del título de la entrada (en caracteres)','Show author'=>'Mostrar autor','Displays the date of the post. Uses the same date format set in General Options.'=>'Muestra la fecha de la entrada. Usa el mismo formato de fecha definido en las opciones generales.','Show date'=>'Mostrar fecha','Length of excerpt (in words)'=>'Longitud del extracto (en palabras)','If the post does not have an excerpt, the plugin will automatically create one containing the number of words specified in the next option.'=>'Si la entrada no tiene extracto, el plugin creará automáticamente uno que contenga el número de palabras especificado en la siguiente opción.','Show post excerpt'=>'Mostrar extracto de la entrada','Enter the custom text that will be displayed if the second option is selected above.'=>'Introduce el texto personalizado que se mostrará si se ha seleccionado arriba la segunda opción.','Custom text'=>'Texto personalizado','Display custom text'=>'Mostrar texto personalizado','Blank output'=>'Salida vacía','Show when no posts are found'=>'Mostrar cuando no haya entradas','Related Posts'=>'Post Relacionados','Displayed before the list of the posts as a master heading'=>'Mostrado antes de la lista de entradas como encabezado maestro','Heading of posts'=>'Encabezado de las entradas','A no-follow link to the plugin homepage will be added as the last item of the related posts.'=>'Un enlace nofollow a la página de inicio del plugin se añadirá como último elemento de las entradas relacionadas.','Link to Contextual Related Posts plugin page'=>'Enlace a la página del plugin Contextual Related Posts','If selected, the meta box will be hidden from anyone who is not an Admin. By default, Contributors and above will be able to see the meta box. Applies only if the above option is selected.'=>'Si selecciona, la caja meta estará oculta para cualquiera que no sea administrador. Por defecto los colaboradores y por encima podrán ver la caja meta. Se aplica solo si está seleccionada la opción de arriba.','Limit meta box to Admins only'=>'Limitar caja meta solo a administradores','This will add the Contextual Related Posts metabox on Edit Posts or Add New Posts screens. Also applies to Pages and Custom Post Types.'=>'Esto añadirá la caja meta de Contextual Related Posts a las pantallas de edición de entradas y de añadir nuevas entradas. También se aplica a páginas y tipos de contenido personalizados.','Show metabox'=>'Mostrar caja meta','If this is checked, FULLTEXT indices generated by Contextual Related Posts are removed from the database if you choose to uninstall/delete the plugin.'=>'Si está marcado, los índices FULLTEXT generados por Contextual Related Posts se eliminarán de la base de datos si decides desinstalar/eliminar el plugin.','Delete FULLTEXT indices on uninstall'=>'Borrar índices FULLTEXT al desinstalar','If this is checked, all settings related to Contextual Related Posts are removed from the database if you choose to uninstall/delete the plugin.'=>'Si esta opción está seleccionada, todos los ajustes relacionados con Contextual Related Posts se eliminarán de la base de datos si decides desinstalar/eliminar el plugin.','Delete options on uninstall'=>'Borrar opciones al desinstalar','Disable display of related posts on AMP pages.'=>'Desactiva la visualización de entradas relacionadas en páginas AMP.','Disable on AMP pages'=>'Desactivar en páginas AMP.','Disable display of related posts on mobile devices. Might not always work with caching plugins.'=>'Desactiva la visualización de entradas relacionadas en dispositivos móviles. Podría no funcionar siempre por los plugins de caché.','Disable on mobile devices'=>'Desactivar en dispositivos móviles','Insert after paragraph number'=>'Insertar después del número del párrafo','Select the relative position of the related posts in the post content. A higher number pushes the related posts later in the content. Any number below 10 is not recommended.'=>'Selecciona la posición relativa de las entradas relacionadas en el contenido de la entrada. Un número mayor coloca las entradas relacionadas más adelante en el contenido. No se recomienda un número inferior a 10.','Display location priority'=>'Mostrar prioridad de ubicación','Other archives'=>'Otros archivos','Tag archives'=>'Archivos de etiquetas','Category archives'=>'Archivos de categorías','Feeds'=>'Feeds','Home page'=>'Página de inicio','Pages'=>'Páginas','Posts'=>'Entradas','If you choose to disable this, please add %1$s to your template file where you want it displayed'=>'Si eliges desactivar esto, por favor, añadi %1$s al archivo de tu plantilla donde quieras que se muestre','Automatically add related posts to'=>'Añadir automáticamente entradas relacionadas a','Cache HTML output'=>'Almacenar en caché el HTML generado','Enabling this will only cache the related posts but not the entire HTML output. This gives you more flexibility at marginally lower performance. Use this if you only have the related posts called with the same set of parameters.'=>'Activando esto solo se almacenarán en caché las entradas relacionadas pero no todo el HTML generado. Esto te ofrece más flexibilidad con un poco de menor rendimiento. Usa esto solo si llamas a las entradas relacionadas con el mismo conjunto de parámetros.','Cache posts only'=>'Almacenar en caché solo las entradas','This screen provides some tools that help maintain certain features of Contextual Related Posts.'=>'Esta pantalla proporciona algunas herramientas para ayudar a mantener ciertas características de Contextual Related Posts.','Styles'=>'Estilos','Thumbnail'=>'Miniatura','This screen provides the various settings for configuring Contextual Related Posts.'=>'Esta pantalla ofrece diversos ajustes para configurar Contextual Related Posts.','General'=>'General','For more information or how to get support visit the <a href="%s" target="_blank">support site</a>.'=>'Para más información sobre cómo obtener soporte vista el <a href="%s" target="_blank">sitio de soporte</a>.','Powered by <a href="%s" rel="nofollow" style="float:none">Contextual Related Posts</a>'=>'Funciona gracias a <a href="%s" rel="nofollow" style="float:none">Contextual Related Posts</a>',' by '=>' por ','Post types to include'=>'Tipos de contenido a incluir',' Randomize posts'=>' Entradas aleatorias','Order posts'=>'Ordenar las entradas','Thumbnail width'=>'Anchura de la miniatura','Thumbnail height'=>'Altura de la miniatura','No thumbnails, only text.'=>'Sin miniaturas, solo texto.','Only thumbnails, no text'=>'Solo miniaturas, sin texto','Thumbnails inline, after title'=>'Miniaturas integradas, después del título','Thumbnails inline, before title'=>'Miniaturas integradas, antes del título','Thumbnail options'=>'Opciones de la miniatura',' Show date?'=>'¿Mostrar la fecha?',' Show author?'=>'¿Mostrar el autor?',' Show excerpt?'=>' ¿Mostrar el extracto?','Offset'=>'Compensar','No. of posts'=>'Número de entradas','Title'=>'Título','Display Related Posts'=>'Mostrar las entradas relacionadas','Related Posts [CRP]'=>'Entradas relacionadas [CRP]','No related posts found'=>'No se han encontrado entradas relacionadas','https://webberzone.com'=>'https://webberzone.com','WebberZone'=>'WebberZone','Display related posts on your website or in your feed. Increase reader retention and reduce bounce rates.'=>'Muestra entradas relacionadas en tu web o en tu feed. Aumenta la retención del lector y reduce las tasas de rebote.','https://webberzone.com/plugins/contextual-related-posts/'=>'https://webberzone.com/plugins/contextual-related-posts/','Contextual Related Posts'=>'Contextual Related Posts']];